example.code:
{
  "server_name": "faion-weather",
  "server_version": "1.2.0",
  "transport": "stdio",
  "auth": {"mode": "none"},
  "tools": [
    {"name": "ping", "description": "Health probe; returns server status and version", "inputSchema": {"type": "object", "properties": {}}},
    {"name": "weather.get_current", "description": "Get current weather for a city by name", "inputSchema": {"type": "object", "required": ["city"], "properties": {"city": {"type": "string", "description": "City name in English, e.g. 'Lisbon'"}}}}
  ],
  "registration": {
    "claude_code_settings": {"mcpServers": {"faion-weather": {"command": "python", "args": ["/srv/mcp/weather/server.py"]}}}
  }
}
